def write_file(relative: str, content: str) -> None:
    path = ROOT / relative
    if path.exists():
        current = path.read_text(encoding="utf-8")
        if current == content:
            print(f"SKIP: {relative} already installed")
            return
        raise RuntimeError(f"Refusing to overwrite non-matching file: {relative}")
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")
    print(f"ADDED: {relative}")


def insert_after(path: Path, anchor: str, addition: str, label: str) -> None:
    text = path.read_text(encoding="utf-8")
    if addition in text:
        print(f"SKIP: {label} already updated")
        return
    if text.count(anchor) != 1:
        raise RuntimeError(f"{label}: expected exactly one anchor")
    path.write_text(text.replace(anchor, anchor + addition, 1), encoding="utf-8")
    print(f"UPDATED: {label}")


def main() -> None:
    for relative, content in FILES.items():
        write_file(relative, content)

    insert_after(
        ROOT / "docs/scenario_comparison_architecture.md",
        COMPARISON_ANCHOR,
        COMPARISON_ADDITION,
        "scenario comparison architecture",
    )
    insert_after(
        ROOT / "docs/desktop_application_architecture.md",
        DESKTOP_ANCHOR,
        DESKTOP_ADDITION,
        "desktop application architecture",
    )
    print("BE-012 application complete.")


if __name__ == "__main__":
    main()
